#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.Managers;
using MVZ2.UI.Level;
using MVZ2Logic.Entities;
using MVZ2Logic.Games;
using MVZ2Logic.Options;
using PVZEngine.Armors;
using UnityEngine;

namespace MVZ2.Entities
{
    public class EntityHPBarSource : IHPBarSource
    {
        public EntityHPBarSource(EntityController controller)
        {
            Controller = controller;
        }

        public bool IsActive()
        {
            if (!Controller.Exists())
                return false;
            var entity = Controller.Entity;
            var level = Controller.Level;
            if (entity.IsPreviewEnemy())
                return false;
            var visibility = entity.GetHPBarVisibility();
            bool shouldShow = visibility == HPBarVisibility.FORCE || (level.ShouldShowHPBars() && visibility != HPBarVisibility.HIDDEN);
            if (!shouldShow || !Controller.ShouldShowHPBarOnEntity())
                return false;
            return true;
        }
        public Vector3 GetPosition()
        {
            return Controller.transform.position + Vector3.up * 0.24f;
        }
        public void UpdateHPBarList(HPBarList list)
        {
            list.gameObject.name = Controller.gameObject.name;
            hpBarBuffer.Clear();
            GetHPBarViewDatas(hpBarBuffer);

            list.SetBarCount(hpBarBuffer.Count);
            for (int i = 0; i < hpBarBuffer.Count; i++)
            {
                list.UpdateBar(i, hpBarBuffer[i]);
            }
        }
        private void GetHPBarViewDatas(List<HPBarViewData> hpBarBuffer)
        {
            var amountMode = Main.OptionsManager.GetHPBarAmountMode();

            if (Controller.ShouldShowMainHPBar())
            {
                var mainViewData = new HPBarViewData()
                {
                    barAmount = Controller.GetMainHPBarAmount(),
                    barColor = Color.red,
                    text = Controller.GetMainHPBarText(amountMode),
                    icon = null
                };
                hpBarBuffer.Add(mainViewData);
            }

            var entity = Controller.Entity;
            var level = Controller.Level;
            foreach (var armorSlot in entity.GetActiveArmorSlots())
            {
                var armor = entity.GetArmorAtSlot(armorSlot);
                if (!Armor.Exists(armor))
                    continue;
                var armorSlotDefinition = level.Game.GetArmorSlotDefinition(armorSlot);
                if (armorSlotDefinition == null)
                    continue;
                if (!Controller.ShouldShowArmorHPBar(armor))
                    continue;

                var icon = Main.GetFinalSprite(armorSlotDefinition.HPBarIcon);
                var viewData = new HPBarViewData()
                {
                    barAmount = Controller.GetArmorHPBarAmount(armor),
                    barColor = armorSlotDefinition.HPBarColor,
                    text = Controller.GetArmorHPBarText(armor, amountMode),
                    icon = icon
                };
                hpBarBuffer.Add(viewData);
            }
        }
        public MainManager Main => MainManager.Instance;
        public EntityController Controller { get; }
        private List<HPBarViewData> hpBarBuffer = new List<HPBarViewData>();
    }
}
